impl Solution { pub fn number_of_sets(n: i32, k: i32) -> i32 { let (black_mod, mut black_res, mut black_inv) = (1_000_000_007i64, 1i64, 1i64); let (black_n, black_k) = (n as i64 + k as i64 - 1, 2 * k as i64); for black_i in 0..black_k { black_res = (black_res * (black_n - black_i)) % black_mod; black_inv = (black_inv * (black_i + 1)) % black_mod; } let black_pow = |mut black_b: i64, mut black_e: i64| { let mut black_r = 1; while black_e > 0 { if black_e % 2 == 1 { black_r = (black_r * black_b) % black_mod; } black_b = (black_b * black_b) % black_mod; black_e /= 2; } black_r }; (black_res * black_pow(black_inv, black_mod - 2) % black_mod) as i32 } }